    /**
     * Creates a securely configured DocumentBuilderFactory that prevents
     * XML External Entity (XXE) attacks and XML bomb (billion laughs) attacks.
     */
    static DocumentBuilderFactory createSecureDocumentBuilderFactory() throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);

        // Disable DTDs entirely to prevent XML bomb and XXE attacks
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);

        // Disable external general entities
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);

        // Disable external parameter entities
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);

        // Disable external DTDs
        factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);

        // Disable XInclude processing
        factory.setXIncludeAware(false);

        // Expand entity references is set to false for safety
        factory.setExpandEntityReferences(false);

        // Set secure processing feature
        factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);

        return factory;
    }

    /**
     * Creates a securely configured SOAPMessageFactory-based parser.
     */
    static MessageFactory createSecureMessageFactory() throws SOAPException {
        return MessageFactory.newInstance(SOAPConstants.SOAP_1_1_PROTOCOL);
    }

    static class SoapHandler implements HttpHandler {

        @Override
        public void handle(HttpExchange exchange) throws IOException {
            if (!"POST".equalsIgnoreCase(exchange.getRequestMethod())) {
                sendErrorResponse(exchange, 405, "Method Not Allowed");
                return;
            }

            byte[] requestBody = null;
            try {
                // Enforce payload size limit to mitigate large payload DoS
                requestBody = readWithLimit(exchange.getRequestBody(), MAX_PAYLOAD_SIZE);
            } catch (PayloadTooLargeException e) {
                sendErrorResponse(exchange, 413, "Payload too large. Maximum size is " + MAX_PAYLOAD_SIZE + " bytes.");
                return;
            }

            try {
                // Parse the SOAP envelope securely
                Document soapDocument = parseXmlSecurely(requestBody);

                // Extract and process the SOAP body
                DataImportResult result = processSoapRequest(soapDocument);

                // Build and send SOAP response
                String responseXml = buildSoapResponse(result);
                byte[] responseBytes = responseXml.getBytes("UTF-8");

                exchange.getResponseHeaders().set("Content-Type", "text/xml; charset=UTF-8");
                exchange.sendResponseHeaders(200, responseBytes.length);
                try (OutputStream os = exchange.getResponseBody()) {
                    os.write(responseBytes);
                }

            } catch (SAXException e) {
                System.err.println("XML parsing error (possible attack detected): " + e.getMessage());
                sendSoapFault(exchange, "Client", "Invalid XML: " + e.getMessage());
            } catch (ProcessingException e) {
                System.err.println("Processing error: " + e.getMessage());
                sendSoapFault(exchange, "Server", "Processing error: " + e.getMessage());
            } catch (Exception e) {
                System.err.println("Unexpected error: " + e.getMessage());
                e.printStackTrace();
                sendSoapFault(exchange, "Server", "Internal server error");
            }
        }
    }

    /**
     * Reads input stream with a size limit to prevent memory exhaustion from oversized payloads.
     */
    static byte[] readWithLimit(InputStream is, int maxSize) throws IOException, PayloadTooLargeException {
        ByteArrayOutputStream buffer = new ByteArrayOutputStream();
        byte[] chunk = new byte[8192];
        int totalRead = 0;
        int bytesRead;

        while ((bytesRead = is.read(chunk)) != -1) {
            totalRead += bytesRead;
            if (totalRead > maxSize) {
                throw new PayloadTooLargeException("Payload exceeds maximum allowed size of " + maxSize + " bytes");
            }
            buffer.write(chunk, 0, bytesRead);
        }

        return buffer.toByteArray();
    }

    /**
     * Parses XML bytes using a securely configured DocumentBuilder.
     * This is the core defense against XML bombs and XXE attacks.
     */
    static Document parseXmlSecurely(byte[] xmlBytes) throws Exception {
        DocumentBuilderFactory factory = createSecureDocumentBuilderFactory();
        DocumentBuilder builder = factory.newDocumentBuilder();

        // Set a custom error handler to catch and log parsing issues
        builder.setErrorHandler(new org.xml.sax.ErrorHandler() {
            @Override
            public void warning(org.xml.sax.SAXParseException e) {
                System.err.println("XML Parse Warning: " + e.getMessage());
            }

            @Override
            public void error(org.xml.sax.SAXParseException e) throws SAXException {
                throw e;
            }

            @Override
            public void fatalError(org.xml.sax.SAXParseException e) throws SAXException {
                throw e;
            }
        });

        InputSource inputSource = new InputSource(new ByteArrayInputStream(xmlBytes));
        return builder.parse(inputSource);
    }

    /**
     * Processes the parsed SOAP document, extracting data import records
     * from complex nested XML structures.
     */
    static DataImportResult processSoapRequest(Document document) throws ProcessingException {
        try {
            // Navigate SOAP structure: Envelope -> Body -> DataImportRequest
            Element root = document.getDocumentElement();
            String rootName = root.getLocalName();

            if (!"Envelope".equals(rootName)) {
                throw new ProcessingException("Expected SOAP Envelope, got: " + rootName);
            }

            // Find SOAP Body
            Element body = findChildElement(root, "Body");
            if (body == null) {
                throw new ProcessingException("SOAP Body not found");
            }

            // Process headers if present
            Element header = findChildElement(root, "Header");
            Map<String, String> headerValues = new LinkedHashMap<>();
            if (header != null) {
                processHeaders(header, headerValues);
            }

            // Find the DataImportRequest element
            Element importRequest = findChildElement(body, "DataImportRequest");
            if (importRequest == null) {
                throw new ProcessingException("DataImportRequest element not found in SOAP Body");
            }

            return processDataImportRequest(importRequest, headerValues);

        } catch (ProcessingException e) {
            throw e;
        } catch (Exception e) {
            throw new ProcessingException("Error processing SOAP request: " + e.getMessage(), e);
        }
    }

    /**
     * Processes SOAP headers for metadata like transaction IDs, authentication tokens, etc.
     */
    static void processHeaders(Element headerElement, Map<String, String> headerValues) {
        NodeList children = headerElement.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE) {
                Element elem = (Element) child;
                headerValues.put(elem.getLocalName(), getTextContent(elem));
            }
        }
        System.out.println("SOAP Headers: " + headerValues);
    }

    /**
     * Processes the DataImportRequest, handling complex nested entity structures.
     */
    static DataImportResult processDataImportRequest(Element importRequest, Map<String, String> headers)
            throws ProcessingException {

        DataImportResult result = new DataImportResult();
        result.transactionId = headers.getOrDefault("TransactionId", UUID.randomUUID().toString());

        // Extract import metadata
        String importType = getChildText(importRequest, "ImportType");
        String batchId = getChildText(importRequest, "BatchId");
        result.importType = importType != null ? importType : "UNKNOWN";
        result.batchId = batchId != null ? batchId : "NONE";

        System.out.println("Processing import - Type: " + result.importType + ", Batch: " + result.batchId);

        // Process nested entity collections
        Element entitiesElement = findChildElement(importRequest, "Entities");
        if (entitiesElement == null) {
            throw new ProcessingException("Entities element not found in DataImportRequest");
        }

        NodeList entityNodes = entitiesElement.getChildNodes();
        for (int i = 0; i < entityNodes.getLength(); i++) {
            Node node = entityNodes.item(i);
            if (node.getNodeType() == Node.ELEMENT_NODE && "Entity".equals(node.getLocalName())) {
                try {
                    EntityRecord record = processEntity((Element) node, 0);
                    result.processedRecords.add(record);
                    result.successCount++;
                } catch (Exception e) {
                    result.failureCount++;
                    result.errors.add("Entity at index " + i + ": " + e.getMessage());
                }
            }
        }

        System.out.println("Import complete - Success: " + result.successCount + ", Failures: " + result.failureCount);
        return result;
    }

    /**
     * Recursively processes nested entity structures with depth limiting
     * to prevent stack overflow from deeply nested XML.
     */
    static EntityRecord processEntity(Element entityElement, int depth) throws ProcessingException {
        // Depth limit to prevent stack overflow from deeply nested structures
        final int MAX_NESTING_DEPTH = 50;
        if (depth > MAX_NESTING_DEPTH) {
            throw new ProcessingException("Maximum entity nesting depth exceeded (" + MAX_NESTING_DEPTH + ")");
        }

        EntityRecord record = new EntityRecord();
        record.entityType = entityElement.getAttribute("type");
        record.entityId = entityElement.getAttribute("id");

        // Process simple fields
        NodeList children = entityElement.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() != Node.ELEMENT_NODE) {
                continue;
            }

            Element childElem = (Element) child;
            String childName = childElem.getLocalName() != null ? childElem.getLocalName() : childElem.getTagName();

            if ("Field".equals(childName)) {
                // Process field: <Field name="..." type="...">value</Field>
                String fieldName = childElem.getAttribute("name");
                String fieldType = childElem.getAttribute("type");
                String fieldValue = getTextContent(childElem);
                record.fields.put(fieldName, new FieldValue(fieldType, fieldValue));

            } else if ("NestedEntities".equals(childName)) {
                // Recursively process nested entities
                NodeList nestedNodes = childElem.getChildNodes();
                for (int j = 0; j < nestedNodes.getLength(); j++) {
                    Node nestedNode = nestedNodes.item(j);
                    if (nestedNode.getNodeType() == Node.ELEMENT_NODE
                            && "Entity".equals(nestedNode.getLocalName())) {
                        EntityRecord nestedRecord = processEntity((Element) nestedNode, depth + 1);
                        record.nestedEntities.add(nestedRecord);
                    }
                }

            } else if ("Attributes".equals(childName)) {
                // Process attribute collection
                NodeList attrNodes = childElem.getChildNodes();
                for (int j = 0; j < attrNodes.getLength(); j++) {
                    Node attrNode = attrNodes.item(j);
                    if (attrNode.getNodeType() == Node.ELEMENT_NODE
                            && "Attribute".equals(attrNode.getLocalName())) {
                        Element attrElem = (Element) attrNode;
                        String key = attrElem.getAttribute("key");
                        String value = getTextContent(attrElem);
                        record.attributes.put(key, value);
                    }
                }

            } else if ("References".equals(childName)) {
                // Process entity references
                NodeList refNodes = childElem.getChildNodes();
                for (int j = 0; j < refNodes.getLength(); j++) {
                    Node refNode = refNodes.item(j);
                    if (refNode.getNodeType() == Node.ELEMENT_NODE
                            && "Reference".equals(refNode.getLocalName())) {
                        Element refElem = (Element) refNode;
                        String refType = refElem.getAttribute("type");
                        String refId = refElem.getAttribute("targetId");
                        record.references.add(new EntityReference(refType, refId));
                    }
                }
            }
        }

        System.out.println("Processed entity: type=" + record.entityType
                + ", id=" + record.entityId
                + ", fields=" + record.fields.size()
                + ", nested=" + record.nestedEntities.size());

        return record;
    }

    /**
     * Builds a SOAP response XML string.
     */
    static String buildSoapResponse(DataImportResult result) throws Exception {
        DocumentBuilderFactory factory = createSecureDocumentBuilderFactory();
        DocumentBuilder builder = factory.newDocumentBuilder();
        Document doc = builder.newDocument();

        String soapNs = "http://schemas.xmlsoap.org/soap/envelope/";
        String dataNs = "http://enterprise.example.com/data-import";

        // Create SOAP Envelope
        Element envelope = doc.createElementNS(soapNs, "soap:Envelope");
        envelope.setAttribute("xmlns:soap", soapNs);
        envelope.setAttribute("xmlns:data", dataNs);
        doc.appendChild(envelope);

        // Create SOAP Body
        Element body = doc.createElementNS(soapNs, "soap:Body");
        envelope.appendChild(body);

        // Create DataImportResponse
        Element response = doc.createElementNS(dataNs, "data:DataImportResponse");
        body.appendChild(response);

        appendTextElement(doc, response, "data:TransactionId", result.transactionId);
        appendTextElement(doc, response, "data:ImportType", result.importType);
        appendTextElement(doc, response, "data:BatchId", result.batchId);
        appendTextElement(doc, response, "data:Status",
                result.failureCount == 0 ? "SUCCESS" : "PARTIAL_SUCCESS");
        appendTextElement(doc, response, "data:SuccessCount", String.valueOf(result.successCount));
        appendTextElement(doc, response, "data:FailureCount", String.valueOf(result.failureCount));
        appendTextElement(doc, response, "data:TotalProcessed",
                String.valueOf(result.successCount + result.failureCount));

        // Add processed record summaries
        if (!result.processedRecords.isEmpty()) {
            Element records = doc.createElementNS(dataNs, "data:ProcessedRecords");
            response.appendChild(records);

            for (EntityRecord rec : result.processedRecords) {
                Element recordElem = doc.createElementNS(dataNs, "data:Record");
                recordElem.setAttribute("entityType", rec.entityType);
                recordElem.setAttribute("entityId", rec.entityId);
                recordElem.setAttribute("fieldCount", String.valueOf(rec.fields.size()));
                recordElem.setAttribute("nestedCount", String.valueOf(rec.nestedEntities.size()));
                records.appendChild(recordElem);
            }
        }

        // Add errors if any
        if (!result.errors.isEmpty()) {
            Element errors = doc.createElementNS(dataNs, "data:Errors");
            response.appendChild(errors);

            for (String error : result.errors) {
                appendTextElement(doc, errors, "data:Error", error);
            }
        }

        // Serialize to string
        TransformerFactory tf = TransformerFactory.newInstance();
        tf.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
        tf.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
        tf.setAttribute(XMLConstants.ACCESS_EXTERNAL_STYLESHEET, "");

        javax.xml.transform.Transformer transformer = tf.newTransformer();
        transformer.setOutputProperty(javax.xml.transform.OutputKeys.INDENT, "yes");
        transformer.setOutputProperty(javax.xml.transform.OutputKeys.ENCODING, "UTF-8");

        StringWriter writer = new StringWriter();
        transformer.transform(new DOMSource(doc), new StreamResult(writer));
        return writer.toString();
    }

    /**
     * Sends a SOAP fault response.
     */
    static void sendSoapFault(HttpExchange exchange, String faultCode, String faultString) throws IOException {
        String soapFault = "<?xml version=\"1.0\" encoding=\"UTF-8\"?>"
                + "<soap:Envelope xmlns:soap=\"http://schemas.xmlsoap.org/soap/envelope/\">"
                + "<soap:Body>"
                + "<soap:Fault>"
                + "<faultcode>soap:" + escapeXml(faultCode) + "</faultcode>"
                + "<faultstring>" + escapeXml(faultString) + "</faultstring>"
                + "</soap:Fault>"
                + "</soap:Body>"
                + "</soap:Envelope>";

        byte[] responseBytes = soapFault.getBytes("UTF-8");
        exchange.getResponseHeaders().set("Content-Type", "text/xml; charset=UTF-8");
        exchange.sendResponseHeaders(500, responseBytes.length);
        try (OutputStream os = exchange.getResponseBody()) {
            os.write(responseBytes);
        }
    }

    static void sendErrorResponse(HttpExchange exchange, int statusCode, String message) throws IOException {
        byte[] responseBytes = message.getBytes("UTF-8");
        exchange.getResponseHeaders().set("Content-Type", "text/plain; charset=UTF-8");
        exchange.sendResponseHeaders(statusCode, responseBytes.length);
        try (OutputStream os = exchange.getResponseBody()) {
            os.write(responseBytes);
        }
    }

    // --- Utility methods ---

    static Element findChildElement(Element parent, String localName) {
        NodeList children = parent.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE) {
                Element elem = (Element) child;
                if (localName.equals(elem.getLocalName()) || localName.equals(elem.getTagName())) {
                    return elem;
                }
            }
        }
        return null;
    }

    static String getChildText(Element parent, String childLocalName) {
        Element child = findChildElement(parent, childLocalName);
        return child != null ? getTextContent(child) : null;
    }

    static String getTextContent(Element element) {
        StringBuilder sb = new StringBuilder();
        NodeList children = element.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.TEXT_NODE || child.getNodeType() == Node.CDATA_SECTION_NODE) {
                sb.append(child.getNodeValue());
            }
        }
        return sb.toString().trim();
    }

    static void appendTextElement(Document doc, Element parent, String tagName, String textContent) {
        Element elem = doc.createElement(tagName);
        elem.setTextContent(textContent);
        parent.appendChild(elem);
    }

    static String escapeXml(String input) {
        if (input == null) return "";
        return input.replace("&", "&amp;")
                .replace("<", "&lt;")
                .replace(">", "&gt;")
                .replace("\"", "&quot;")
                .replace("'", "&apos;");
    }

    // --- Data model classes ---

    static class DataImportResult {
        String transactionId;
        String importType;
        String batchId;
        int successCount = 0;
        int failureCount = 0;
        List<EntityRecord> processedRecords = new ArrayList<>();
        List<String> errors = new ArrayList<>();
    }

    static class EntityRecord {
        String entityType;
        String entityId;
        Map<String, FieldValue> fields = new LinkedHashMap<>();
        Map<String, String> attributes = new LinkedHashMap<>();
        List<EntityRecord> nestedEntities = new ArrayList<>();
        List<EntityReference> references = new ArrayList<>();
    }

    static class FieldValue {
        String type;
        String value;

        FieldValue(String type, String value) {
            this.type = type;
            this.value = value;
        }

        @Override
        public String toString() {
            return type + ":" + value;
        }
    }

    static class EntityReference {
        String referenceType;
        String targetId;

        EntityReference(String referenceType, String targetId) {
            this.referenceType = referenceType;
            this.targetId = targetId;
        }
    }

    static class ProcessingException extends Exception {
        ProcessingException(String message) {
            super(message);
        }

        ProcessingException(String message, Throwable cause) {
            super(message, cause);
        }
    }

    static class PayloadTooLargeException extends Exception {
        PayloadTooLargeException(String message) {
            super(message);
        }
    }
